import React, { useEffect, useState } from "react";
import { Button, Typography, Box, Alert, CircularProgress } from "@mui/material";
import { useNavigate } from "react-router-dom";
import { getRiderStatus } from "../../services/api";

export default function RiderDashboard() {
  const navigate = useNavigate();
  const [rider, setRider] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  useEffect(() => {
    const token = localStorage.getItem("token");
    if (!token) {
      navigate("/login");
      return;
    }

    getRiderStatus(token)
  .then((res) => {
    console.log("✅ Rider status response:", res.data);
    setRider(res.data.user);
    setLoading(false);
  })
  .catch((err) => {
    console.error("❌ Error loading rider data:", err.response?.data || err);
    setError(err.response?.data?.message || "Error loading rider data");
    setLoading(false);
  });

  }, [navigate]);

  const handleLogout = () => {
    localStorage.removeItem("token");
    localStorage.removeItem("role");
    navigate("/login");
  };

  if (loading) return <Box sx={{ p: 4, textAlign: "center" }}><CircularProgress /></Box>;
  if (error) return <Box sx={{ p: 4 }}><Alert severity="error">{error}</Alert></Box>;

  // ✅ Show waiting screen until approved
  if (rider?.approvalStatus === "pending") {
    return (
      <Box sx={{ p: 4 }}>
        <Typography variant="h5" sx={{ mb: 2 }}>Verification in Progress</Typography>
        <Typography>Your documents are under review. Please wait for admin approval.</Typography>
        <Button sx={{ mt: 3 }} variant="contained" color="error" onClick={handleLogout}>Logout</Button>
      </Box>
    );
  }

  // ✅ If not approved yet and no docs → send to upload page
  if (rider?.approvalStatus !== "approved") {
    navigate("/upload-docs");
    return null;
  }

  // ✅ Approved → Show Rider Dashboard
  return (
    <Box sx={{ p: 4 }}>
      <Typography variant="h4" sx={{ mb: 2 }}>Welcome, {rider.fullName} 🚖</Typography>
      <Typography variant="body1" sx={{ mb: 3 }}>
        You can now access your rides, track trips, and earnings.
      </Typography>
      <Button variant="contained" color="primary" onClick={handleLogout}>Logout</Button>
    </Box>
  );
}
